--
-- Estructura de tabla para la tabla `product_locations`
--

CREATE TABLE `product_locations` (
  `id` bigint(20) UNSIGNED NOT NULL,
  `product_id` bigint(20) UNSIGNED NOT NULL,
  `latitude` decimal(10,8) NOT NULL COMMENT 'Latitud de la ubicación',
  `longitude` decimal(11,8) NOT NULL COMMENT 'Longitud de la ubicación',
  `address` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Dirección formateada (opcional)',
  `is_active` tinyint(1) NOT NULL DEFAULT 1 COMMENT 'Activar/desactivar ubicación',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

